(1754, 'Nishant Sharma', 'nishant.developer22@gmail.com', 'Sfvkds h Bj', 'ar-vr-app-development', 'Page rank tech', 'Re: Website Design & development service', 'Hi,\r\n\r\nI was just browsing your website and I came up with a great plan to re-develop your website using the latest technology to generate additional revenue and beat your opponents. \r\n\r\nI\'m an excellent web developer capable of almost anything you can come up with, and my costs are affordable for nearly everyone.\r\n\r\nI would be happy to send you \"Quotes\", РђюProposalРђЮ Past work Details, \"Our Packages\", and РђюOffersРђЮ!\r\n\r\nThanks in advance,\r\nNishant (Business Development Executive)', '2024-04-05 11:31:06', '2024-04-05 11:31:06'),
(1989, 'Akshay Sharma', 'akshay.pinblooms@gmail.com', '+91 9785311511', 'mobile-app-qa-and-testing', 'Pin Blooms Technology Pvt. Ltd.', 'React Native Developers Team Available for Project/Contractual Basis: Remotely', 'Hello, \r\n\r\nWarm Greetings!\r\n\r\nI am Akshay Sharma, associated with Pin Blooms Technology Pvt. Ltd as a Business Development manager. \r\nPinBlooms Technologies Pvt Ltd is a registered IT company in India that offers a dedicated team of 2+ years of experience in React Native developers for full-time remote work. \r\n\r\n\r\nOur React Native professionals have good knowledge of the following front-end technologies like JavaScript, CSS, JSX, ES6, React Native, Debugging & Testing, Git, Api Integration, React, Redux, UI/UX design, Deployment and Hot Reloading.\r\n\r\n\r\nKindly refer to the below links for our React Native work samples:\r\nhttps://play.google.com/store/apps/details?id=com.asanly&pcampaignid=web_share&pli=1\r\nhttps://play.google.com/store/apps/details?id=com.ottersclub.club&hl=en-IN&pli=1\r\nhttps://play.google.com/store/apps/details?id=com.silae.factoryops\r\nOur resources are available full-time/part-time/project basis to work on your projects.', '2024-06-11 08:06:01', '2024-06-11 08:06:01'),
(2201, 'Sagar Ali', 'business@johnacademy.co.uk', '02039233962', 'mobile-app-development', 'John Academy', 'E-Learning Partnership Proposal', 'Hi,\r\nI am Sagar, the Business Development Manager at John Academy, a reputable provider of online courses. We offer over 2500 globally recognised courses and have eight years of experience in the Ed-Tech sector.\r\nCurrently, I am exploring the possibility of forming a partnership with you to offer our courses under your brand. We provide CPD-accredited courses and can customise content based on your requirements. This partnership has the potential to be mutually beneficial. I am keen to discuss this further.\r\nIf you are interested in learning more about our courses and exploring potential collaboration opportunities, I would be happy to schedule a meeting at your convenience.\r\nFor further details about us, please visit John Academy.\r\nWarm regards,\r\nSagar', '2024-06-25 12:10:46', '2024-06-25 12:10:46'),
(2204, 'Muhammad Ali', 'business@johnacademy.co.uk', '02039233962', 'Select', 'John Academy', 'E-Learning Partnership Proposal', 'Hi,\r\n\r\nThis is Muhammad from John Academy. I work here as a business development manager. With the experience of  last eight years, we are an industry-leading Ed-Tech company with over 2500 global standard CPD-accredited online self-paced courses covering various subjects.\r\n\r\nAt the moment, we are seeking partnership to reselling our courses to your audience. We have several other partnership models that I would be happy to discuss.\r\n\r\nPlease let me know if you find this proposal appealing, and we can arrange a meeting to explore it further.\r\n\r\nRegards,\r\nMuhammad', '2024-07-03 04:04:29', '2024-07-03 04:04:29'),
