(2798, 'Davidgfedob', 'gashish-i-shishki@kypit-v-ukraine.online', '85311791975', '-', '-', 'лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лБл║Лђл░лИлйлх? лАлљлЎлб - KOKAINES.STORE лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ лџлИлхл▓, лъл┤лхЛЂЛЂл░, лЏЛїл▓лЙл▓, лЦл░ЛђЛїл║лЙл▓ лИ л┤Лђ', 'лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лБл║Лђл░лИлйлх? лАлљлЎлб - KOKAINES.STORE лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ лџлИлхл▓, лъл┤лхЛЂЛЂл░, лЏЛїл▓лЙл▓, лЦл░ЛђЛїл║лЙл▓ лИ л┤Лђ \r\n. \r\n. \r\n. \r\n. \r\n. \r\nлџл░л║ лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лџлИлхл▓лх? лАлљлЎлб - |https://kokaines.store/| \r\nлГл║ЛЂЛѓл░лилИ лИ люлћлюлљ ЛЂ л┤лЙЛЂЛѓл░л▓л║лЙл╣ л▓ ЛђЛЃл║лИ лџЛЃл┐лИЛѓЛї? лАлљлЎлб - |https://kokaines.store/| \r\nлГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л┐лЙ лБл║Лђл░лИлйлх лџЛЃл┐лИЛѓЛї? лАлљлЎлб - |https://kokaines.store/| \r\nлГл║ЛЂЛѓл░лилИ лИ люлћлюлљ лЦл░ЛђЛїл║лЙл▓, лъл┤лхЛЂЛЂл░, лЏЛїл▓лЙл▓, лўл▓л░лйлЙ-лцЛђл░лйл║лЙл▓ЛЂл║? лАлљлЎлб - |https://kokaines.store/| \r\nлГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЊлЙЛђлЙл┤л░ЛЁ лБл║Лђл░лИлйЛІ ЛЂ л┤лЙЛЂЛѓл░л▓л║лЙл╣ л▓ ЛђЛЃл║лИ? лАлљлЎлб - |https://kokaines.store/| \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\n. \r\nлЊЛЃл│л╗ л▒лЙЛѓ, ЛЇЛѓлЙ Лѓлхл▒лх - \r\nлџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лџлИлхл▓лх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЦл░ЛђЛїл║лЙл▓лх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лъл┤лхЛЂЛЂлх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лћлйлхл┐Лђлх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЏЛїл▓лЙл▓лх? \r\nлџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЌл░л┐лЙЛђлЙлХЛїлх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лџЛђлИл▓лЙл╝ лалЙл│ЛЃ? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЮлИл║лЙл╗л░лхл▓лх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лњлИлйлйлИЛєлх? \r\nлџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лДлхЛђлйлИл│лЙл▓лх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЪлЙл╗Лѓл░л▓лх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЦлхЛђЛЂлЙлйлх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЦл╝лхл╗ЛїлйлИЛєл║лЙл╝? \r\nлџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лДлхЛђл║л░ЛЂЛЂл░ЛЁ? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лДлхЛђлйлЙл▓Лєл░ЛЁ? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лќлИЛѓлЙл╝лхЛђлх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лАЛЃл╝л░ЛЁ? \r\nлџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лалЙл▓лйлЙ? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лўл▓л░лйлЙ лцЛђл░лйл║лЙл▓ЛЂл║лх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лблхЛђлйлЙл┐лЙл╗лх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лџЛђлЙл┐лИл▓лйлИЛєл║лЙл╝? \r\nлџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЏЛЃЛєл║лх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лџЛђлхл╝лхлйЛЄЛЃл│лх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЉлхл╗лЙл╣ ЛєлхЛђл║л▓лИ? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лБлХл│лЙЛђлЙл┤лх? \r\nлџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЉЛђлЙл▓л░Лђл░ЛЁ? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЮлИл║лЙл┐лЙл╗лх? лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лЪл░л▓л╗лЙл│Лђл░л┤лх? \r\nлЪлЙл║л░ л┐лЙл║л░ лЊЛЃл│л╗ л▒лЙЛѓ, Лђл░л┤ л▒ЛІл╗ л▓ЛЂЛѓЛђлхЛЄлИ ЛЂ ЛѓлЙл▒лЙл╣! \r\nлблхл│лИ лЙл▒ЛЅлхл│лЙ л┐лЙл╗ЛїлилЙл▓л░лйлИЛЈ - \r\nлюл░л║ЛЂлИл╝л░л╗ЛїлйлЙл│лЙ л║л░ЛЄлхЛЂЛѓл▓л░ лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л╝лЙлХлйлЙ л║ЛЃл┐лИЛѓЛї ЛѓлЙл╗Лїл║лЙ л▓ лйл░Лѕлхл╝ л╝л░л│л░лилИлйлх, Лѓл░л║ л║л░л║ лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лБл║Лђл░лИлйлх лйлхЛђлхл░л╗ЛїлйлЙ л│л┤лх ЛѓлЙ л▓ \r\nл┤ЛђЛЃл│лЙл╝ л╝лхЛЂЛѓлх. лЮл░ЛѕлИ л┐ЛђлЙЛёлхЛЂЛЂлИлЙлйл░л╗ЛїлйЛІлх Лђл░л▒лЙЛѓлйлИл║лИ л║л░ЛЄлхЛЂЛѓл▓лхлйлйлЙ Лђл░лил║л╗л░л┤ЛІл▓л░ЛјЛѓ лил░л║л╗л░л┤л║лИ лИ л┐лхЛђлхл┤л░ЛјЛѓ л┐лЙЛЂЛІл╗л║лИ ЛЂ лГл║ЛЂЛѓл░лилИ лИ люлћлюлљлЙл╝ л║ЛђЛЃл│л╗лЙЛЂЛЃЛѓлЙЛЄлйлЙ! \r\nлЮлх л▓лилИЛђл░ЛЈ лйл░ л║лЙл╝лхлйл┤л░лйЛѓЛЂл║лИл╣ ЛЄл░ЛЂ, л▓лЙлхлйлйлЙлх л▓Лђлхл╝ЛЈ, ЛЃл│ЛђлЙлиЛЃ л╗лИЛЄлйлЙл╣ л▒лхлилЙл┐л░ЛЂлйлЙЛЂЛѓлИ - лйл░ЛѕлИ лил░л║л╗л░л┤ЛЄлИл║лИ ЛђлЙлил║л╗л░л┤ЛІл▓л░ЛјЛѓ лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л║ЛђЛЃл│л╗лЙЛЂЛЃЛѓлЙЛЄлйлЙ. \r\nлљл▒ЛЂлЙл╗ЛјЛѓлйлЙ л▓ЛЂлх лил░л║л╗л░л┤л║лИ лГл║ЛЂЛѓл░лилИ лИ люлћлюлљл░ ЛЂ л│л░Лђл░лйЛѓлИлхл╣, л┐лЙ ЛЇЛѓлЙл╝ЛЃ ЛЃ лйл░ЛЂ Лѓл░л║ л╝лйлЙл│лЙ л┐лЙл║ЛЃл┐л░Лѓлхл╗лхл╣, л║лЙЛѓлЙЛђЛІлх л╗Лјл▒ЛЈЛѓ, ЛєлхлйЛЈЛѓ лИ ЛЁлЙЛѓЛЈЛѓ лџЛЃл┐лИЛѓЛї лЮл░Лѕ лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ. \r\nлџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ ЛЂ л┤лЙЛЂЛѓл░л▓л║лЙл╣ л▓ ЛђЛЃл║лИ лхЛЂЛѓЛї л▓лЙлил╝лЙлХлйлЙЛЂЛѓЛї л▓ Лѓл░л║лИЛЁ л│лЙЛђлЙл┤л░ЛЁ л║л░л║ лџлИлхл▓, лЦл░ЛђЛїл║лЙл▓, лЏЛїл▓лЙл▓, лћлйлхл┐Лђ, лЮлИл║лЙл╗л░лхл▓ лИ л┤ЛђЛЃл│лИлх. \r\nлџл░ЛЄлхЛЂЛѓл▓лЙ л║л░лХл┤лЙл╣ л┐л░ЛђЛѓлИлИ л┐ЛђлЙл▓лхЛђЛЈлхл╝ л╗лИЛЄлйлЙ, л┐лЙ ЛЇЛѓлЙл╝ЛЃ лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лџлИлхл▓лх лИл╗лИ лЏЛїл▓лЙл▓лх, лЦл░ЛђЛїл║лЙл▓лх лИл╗лИ лъл┤лхЛЂЛЂлх л╝лЙлХлйлЙ лйлх лЙл┐л░ЛЂл░ЛЈЛЂЛї. \r\nлџлЙл│л┤л░ лил▓ЛЃЛЄлИЛѓ ЛёЛђл░лил░ \"лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лБл║Лђл░лИлйлх\" - ЛѓлЙ л║л░лХл┤ЛІл╣ ЛЃл▓л░лХл░ЛјЛЅлИл╣ ЛЂлхл▒ЛЈ лБл║Лђл░лИлйлхЛє ЛЂЛђл░лиЛЃ лХлх л▓ЛЂл┐лЙл╝лИлйл░лхЛѓ лйл░Лѕ ЛЂл░л╣Лѓ, л┐лЙЛѓлЙл╝ЛЃ ЛЄЛѓлЙ ЛѓлЙл╗Лїл║лЙ \r\nЛѓЛЃЛѓ л╝лЙлХлйлЙ лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л▓ лБл║Лђл░лИлйлх л▓ л▓лИл┤лх л│лИл┤ЛђлЙЛЁл╗лЙЛђлИл┤л░ л▒лхли л┐ЛђлИл╝лхЛЂлхл╣, ЛЄлИЛЂЛѓлЙЛѓл░ лГл║ЛЂЛѓл░лилИ лИ люлћлюлљл░ л▓ ЛЃл║Лђл░лИлйлх ЛЂлЙЛЂЛѓл░л▓л╗ЛЈлхЛѓ 93-98% лЊлЦлћ. \r\nлЮлхЛѓ Лђл░лилйлИЛєЛІ - лйл░ л┐Лђл░лил┤лйлИл║, лйл░ л┤лхлйЛї ЛђлЙлХл┤лхлйЛїлх, лЮл░ лЮлЙл▓ЛІл╣ л│лЙл┤, л┐ЛђлЙЛЂЛѓлЙ л┐лЙл│ЛЃл╗ЛЈЛѓЛї - лЮл░Лѕ ЛЂл░л╣Лѓ лйлх л┐лЙл┤л▓лхл┤лхЛѓ лЮлўлџлълЊлћлљ! лў л▓ЛЂлхл│л┤л░ лџЛЃл┐лИЛѓЛї лГл║ЛЂЛѓл░лилИ лИ люлћлюлљ л╝лЙлХлйлЙ!', '2025-03-26 13:38:19', '2025-03-26 13:38:19'),
(2799, 'ciklonnyy_uckr', 'remseimadiff1980@larpan-mobi4omes.ru', '88359667531', '-', '-', 'ЛєлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ л┤л╗ЛЈ ЛЂЛѓЛђлЙлИЛѓлхл╗ЛїлйлЙл│лЙ л┐ЛІл╗лхЛЂлЙЛЂл░', 'лдлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ л┤л╗ЛЈ ЛЂЛѓЛђлЙлИЛѓлхл╗ЛїлйлЙл│лЙ л┐ЛІл╗лхЛЂлЙЛЂл░: лЙЛЂлЙл▒лхлйлйлЙЛЂЛѓлИ лИ л┐ЛђлхлИл╝ЛЃЛЅлхЛЂЛѓл▓л░, л▓ЛЂЛЉ. \r\nлЪЛђлхлИл╝ЛЃЛЅлхЛЂЛѓл▓л░ ЛєлИл║л╗лЙлйлйлЙл│лЙ ЛёлИл╗ЛїЛѓЛђл░ л┤л╗ЛЈ л▓л░Лѕлхл│лЙ л┐ЛІл╗лхЛЂлЙЛЂл░, ЛёЛЃлйл║ЛєлИлИ. \r\nлЏЛЃЛЄЛѕлИлх ЛєлИл║л╗лЙлйлйЛІлх ЛёлИл╗ЛїЛѓЛђЛІ л┤л╗ЛЈ ЛЂЛѓЛђлЙлИЛѓлхл╗ЛїлйЛІЛЁ л┐ЛІл╗лхЛЂлЙЛЂлЙл▓, лЙЛЂл▓л░лИл▓л░л╣Лѓлх. \r\nлЪЛђлИлйЛєлИл┐ЛІ Лђл░л▒лЙЛѓЛІ ЛєлИл║л╗лЙлйлйлЙл│лЙ ЛёлИл╗ЛїЛѓЛђл░ л┤л╗ЛЈ л┐ЛІл╗лхЛЂлЙЛЂлЙл▓, Лђл░лилйлЙлЙл▒Лђл░лилИлх л▓л░ЛђлИл░лйЛѓлЙл▓. \r\nлБЛЂЛѓл░лйлЙл▓л║л░ лИ лЙл▒ЛЂл╗ЛЃлХлИл▓л░лйлИлх ЛєлИл║л╗лЙлйлйлЙл│лЙ ЛёлИл╗ЛїЛѓЛђл░, л┤л╗ЛЈ л▓ЛЂлхЛЁ лХлхл╗л░ЛјЛЅлИЛЁ. \r\nлъЛЂлйлЙл▓лйЛІлх л┐ЛђлхлИл╝ЛЃЛЅлхЛЂЛѓл▓л░ ЛєлИл║л╗лЙлйлйлЙл│лЙ ЛёлИл╗ЛїЛѓЛђл░, лИлиЛЃЛЄл░л╣Лѓлх. \r\nлдлИл║л╗лЙлйлйЛІлх ЛёлИл╗ЛїЛѓЛђЛІ лИ лИЛЁ л▓л╗лИЛЈлйлИлх лйл░ л║л░ЛЄлхЛЂЛѓл▓лЙ ЛЃл▒лЙЛђл║лИ, л┐Лђл░л║ЛѓлИЛЄлхЛЂл║лИл╝лИ л┐ЛђлИл╝лхЛђл░л╝лИ. \r\nлџл░л║ л▓ЛІл▒Лђл░ЛѓЛї лИл┤лхл░л╗ЛїлйЛІл╣ ЛєлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ?, л▓ЛЂлх, ЛЄЛѓлЙ лйЛЃлХлйлЙ лилйл░ЛѓЛї. \r\nлџл░л║ ЛЄлИЛЂЛѓлИЛѓЛї ЛєлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ?, л┐лЙЛЂл╝лЙЛѓЛђлИл╝ лйл░. \r\nлдлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ л▓ л▓л░Лѕлхл╝ л┐ЛІл╗лхЛЂлЙЛЂлх: ЛЂЛѓлЙлИЛѓ л╗лИ?, ЛѓлхЛЁлйлЙл╗лЙл│лИЛЄлхЛЂл║лИЛЁ л┐ЛђлЙЛђЛІл▓л░ЛЁ. \r\nлџл░л║ л▓ЛІл▒Лђл░ЛѓЛї ЛёлИл╗ЛїЛѓЛђ л┤л╗ЛЈ ЛЂЛѓЛђлЙлИЛѓлхл╗ЛїлйлЙл│лЙ л┐ЛІл╗лхЛЂлЙЛЂл░?, л┐лЙлилйл░л║лЙл╝ЛїЛѓлхЛЂЛї. \r\nлдлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ: ЛЂЛѓлЙлИЛѓ л╗лИ?, лЙЛЂлйлЙл▓лйЛІлх ЛёЛЃлйл║ЛєлИлИ. \r\nлдлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ: л▓л░Лѕ л┐лхЛђл▓ЛІл╣ Лѕл░л│ л║ ЛЄлИЛЂЛѓлЙЛѓлх, л▓ЛЂлх ЛѓлЙлйл║лЙЛЂЛѓлИ. \r\nлдлИл║л╗лЙлйлйЛІлх ЛёлИл╗ЛїЛѓЛђЛІ: л║л░ЛЄлхЛЂЛѓл▓лЙ лИ ЛЇЛёЛёлхл║ЛѓлИл▓лйлЙЛЂЛѓЛї, Лђл░лилйЛІлх ЛѓлхЛЁлйлЙл╗лЙл│лИлИ. \r\nлџл░л║ ЛєлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ ЛЃл╗ЛЃЛЄЛѕл░лхЛѓ л║л░ЛЄлхЛЂЛѓл▓лЙ ЛЃл▒лЙЛђл║лИ?, ЛЂ лйл░ЛѕлИл╝лИ Лђлхл║лЙл╝лхлйл┤л░ЛєлИЛЈл╝лИ. \r\nлЪлЙЛЄлхл╝ЛЃ ЛєлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ Рђћ ЛЇЛѓлЙ л╗ЛЃЛЄЛѕлИл╣ л▓ЛІл▒лЙЛђ?, лЙл▒ЛЂЛЃлХл┤л░лхл╝. \r\nлДЛѓлЙ Лѓл░л║лЙлх ЛєлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ?, л▓ЛІЛЈЛЂлйЛЈлхл╝. \r\nлдлИл║л╗лЙлйлйЛІлх ЛёлИл╗ЛїЛѓЛђЛІ: лИлйл▓лхЛЂЛѓлИЛєлИЛЈ л▓ ЛЄлИЛЂЛѓлЙЛѓЛЃ, л░лйл░л╗лИлилИЛђЛЃлхл╝. \r\nлЮЛЃлХлхлй л╗лИ л▓л░л╝ ЛєлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ?, ЛЃлилйл░л╣Лѓлх. \r\nЛєлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ л┤л╗ЛЈ ЛЂЛѓЛђлЙлИЛѓлхл╗ЛїлйлЙл│лЙ л┐ЛІл╗лхЛЂлЙЛЂл░ <a href=https://wildberries.ru/catalog/353414029/detail.aspx/>ЛєлИл║л╗лЙлйлйЛІл╣ ЛёлИл╗ЛїЛѓЛђ л┤л╗ЛЈ ЛЂЛѓЛђлЙлИЛѓлхл╗ЛїлйлЙл│лЙ л┐ЛІл╗лхЛЂлЙЛЂл░</a> .', '2025-03-27 12:52:26', '2025-03-27 12:52:26'),
