(2858, 'Ismaeel Rashid', 'themoddermods@gmail.com', '+201117700421', 'mobile-app-development', 'themoddermods', 'Game Acquisition Opportunity', 'Hello,\r\n\r\nI am Ismaeel Rashid, the owner/manager of Skru card game App.\r\nThe app is from top 3 card game apps in Egypt. It has 1M+ first time downloads.\r\nContact me if you are interested in acquiring the app.\r\n\r\nhttps://play.google.com/store/apps/details?id=com.skrew.skroo.skru\r\nhttps://apps.apple.com/eg/app/skru/id6478879388', '2025-04-20 17:07:04', '2025-04-20 17:07:04'),
(2859, 'MarinaFup', 'vaor.ru2020@gmail.com', '86831975533', '-', '-', 'лўЛЂЛѓлЙЛђлИЛЈ л┐ЛђлЙЛЂЛѓлИЛѓЛЃЛѓл║лИ люл░ЛђлИлйЛІ: лџлЙЛђлЙл╗лхл▓ лИ лЏлЙл▒лйЛЈ', '<a href=https://korolev.prostitutkivse.com/>лЪЛђлЙЛЂЛѓлИЛѓЛЃЛѓл║лИ лџлЙЛђлЙл╗лхл▓</a> \r\n<a href=https://lobnja.prostitutkivse.com/>лЪЛђлЙЛЂЛѓлИЛѓЛЃЛѓл║лИ лЏлЙл▒лйЛЈ</a> \r\n \r\nлюл░ЛђлИлйл░ л┐ЛђлИлхЛЁл░л╗л░ л▓ лџлЙЛђлЙл╗ЛЉл▓ лИли л┐ЛђлЙл▓лИлйЛєлИлИ л▓ 18 л╗лхЛѓ, л╝лхЛЄЛѓл░ЛЈ лЙ Лђл░л▒лЙЛѓлх л▓ лйл░ЛЃЛЄлйлЙл╝ л│лЙЛђлЙл┤л║лх. \r\nлЮлЙ л▒лхли лЙл▒Лђл░лилЙл▓л░лйлИЛЈ лИ ЛЂл▓ЛЈлилхл╣ ЛЃЛЂЛѓЛђлЙлИл╗л░ЛЂЛї л╗лИЛѕЛї лЙЛёлИЛєлИл░лйЛѓл║лЙл╣. лЌл░Лђл┐л╗л░ЛѓЛІ лйлх ЛЁл▓л░Лѓл░л╗лЙ, лИ л┐лЙл┤ЛђЛЃл│л░ л┐Лђлхл┤л╗лЙлХлИл╗л░ ┬Фл╗лхл│л║лИл╣ лил░Лђл░л▒лЙЛѓлЙл║┬╗. \r\nлЪлхЛђл▓ЛІл╣ л║л╗лИлхлйЛѓ л▒ЛІл╗ л│ЛђЛЃл▒ЛІл╝, лйлЙ л┤лхлйЛїл│лИ ЛЃЛЂл┐лЙл║лЙлИл╗лИ ЛЂлЙл▓лхЛЂЛѓЛї. \r\n \r\n<a href=https://korolev.prostitutkivse.com/list.php?g=0>лЪЛђлЙЛЂЛѓлИЛѓЛЃЛѓл║лИ лџлЙЛђлЙл╗лхл▓ л▓ЛІлхлил┤</a> \r\nлАлЙ л▓Лђлхл╝лхлйлхл╝ люл░ЛђлИлйл░ л┐лхЛђлхЛѕл╗л░ лйл░ лИлйл┤лИл▓лИл┤ЛЃл░л╗ЛїлйЛІлх л▓ЛІлилЙл▓ЛІ, ЛЂлйлИл╝л░ЛЈ л║лЙл╝лйл░ЛѓЛЃ л▓ лЏлЙл▒лйлх. \r\nлЌл┤лхЛЂЛї л║л╗лИлхлйЛѓлЙл▓ л▒ЛІл╗лЙ л▒лЙл╗ЛїЛѕлх Рђћ лЙЛѓ л│л░ЛЂЛѓл░Лђл▒л░л╣ЛѓлхЛђлЙл▓ л┤лЙ л╝лхЛЂЛѓлйЛІЛЁ л▒лИлилйлхЛЂл╝лхлйлЙл▓. лъл┤лИлй, ┬Фл┐лЙЛЂЛѓлЙЛЈлйлйЛІл╣┬╗, л┤л░лХлх л┤л░ЛђлИл╗ л┐лЙл┤л░Лђл║лИ, лйлЙ ЛѓЛђлхл▒лЙл▓л░л╗ exclusivity. \r\nлълйл░ ЛЂлЙл│л╗л░ЛЂлИл╗л░ЛЂЛї, лйл░л┤лхЛЈЛЂЛї лйл░ ЛЂЛѓл░л▒лИл╗ЛїлйлЙЛЂЛѓЛї, лйлЙ лЙлй лИЛЂЛЄлхли л┐лЙЛЂл╗лх лил░л┤лхЛђлХл░лйлИЛЈ лил░ л╝лЙЛѕлхлйлйлИЛЄлхЛЂЛѓл▓лЙ. \r\n \r\n<a href=https://korolev.prostitutkivse.com/search.php?submit=submit&vhmin=3000>лћлхЛѕлхл▓ЛІлх ЛђлЙЛЂЛѓлИЛѓЛЃЛѓл║лИ лџлЙЛђлЙл╗лхл▓</a> \r\nлњ 25 люл░ЛђлИлйл░ л┐лЙл┐л░л╗л░ л▓ лЙл▒л╗л░л▓ЛЃ. лел░лйЛѓл░лХ л╝лхлйЛѓлЙл▓ лил░л▒Лђл░л╗ л┐лЙЛЂл╗лхл┤лйлИлх ЛЂл▒лхЛђлхлХлхлйлИЛЈ. \r\nлълйл░ л┐ЛІЛѓл░л╗л░ЛЂЛї ЛЃл╣ЛѓлИ, ЛЃЛЂЛѓЛђлЙлИл▓ЛѕлИЛЂЛї л┐ЛђлЙл┤л░л▓ЛєлЙл╝, лйлЙ л┤лЙл╗л│лИ л▓лхЛђлйЛЃл╗лИ лхЛЉ л▓ л┐ЛђлЙЛёлхЛЂЛЂлИЛј. \r\n \r\n<a href=https://lobnja.prostitutkivse.com/list.php?g=0>лЪЛђлЙЛЂЛѓлИЛѓЛЃЛѓл║лИ лЏлЙл▒лйЛЈ л▓ЛІлхлил┤</a> \r\nлАлхл╣ЛЄл░ЛЂ лхл╣ 30. лълйл░ л▓ЛЂЛЉ лхЛЅЛЉ Лђл░л▒лЙЛѓл░лхЛѓ, лйлЙ ЛЃлХлх л┐л╗л░лйлИЛђЛЃлхЛѓ лЙЛѓл║ЛђЛІЛѓЛї л╝л░лйлИл║ЛјЛђлйЛІл╣ ЛЂл░л╗лЙлй Рђћ л║лЙл┐лИЛѓ л┤лхлйЛїл│лИ лИ ЛЃЛЄлИЛѓЛЂЛЈ. \r\n┬ФлЦлЙЛЄЛЃ лил░л▒ЛІЛѓЛї ЛЇЛѓлЙЛѓ л░л┤┬╗, Рђћ л│лЙл▓лЙЛђлИЛѓ лЙлйл░, лил░ЛѓЛЈл│лИл▓л░ЛЈЛЂЛї ЛЂлИл│л░ЛђлхЛѓлЙл╣ ЛЃ л▓лЙл║лил░л╗л░ л▓ лџлЙЛђлЙл╗ЛЉл▓лх. \r\n \r\n<a href=https://lobnja.prostitutkivse.com/search.php?submit=submit&vhmin=3000>лћлхЛѕлхл▓ЛІлх л┐ЛђлЙЛЂЛѓлИЛѓЛЃЛѓл║лИ лЏлЙл▒лйЛЈ</a>', '2025-04-21 12:21:27', '2025-04-21 12:21:27'),
