(32, NULL, 'portfolio/2a7e68518538fa26db7021503998296c.webp', 'portfolio/back-images/c1e82128d9b0e11c968187f3582467e7.webp', 'Royal Ride', 'Royal Ride is a ride-booking mobile application designed and developed by AppsNation to provide a smooth, reliable, and user-friendly transportation experience. The app focuses on intuitive navigation, real-time booking features, and a clean interface that ensures convenience, efficiency, and seamless interaction for both riders and drivers.', NULL, NULL, NULL, NULL, 'Mobile', 1, NULL, 'case-studies/royal-ride-app', NULL, 6, 7, 1, '2025-12-08 15:53:34', '2026-01-28 08:27:42'),
(33, NULL, 'portfolio/fcc802a31f2133144eb00dbffcdf0bd4.webp', 'portfolio/back-images/a5dc4be3786fad67f5086e927e90917c.webp', 'Boujee Beachin', 'Boujee Beachin is a lifestyle-focused beach discovery mobile app designed and developed by AppsNation. The app helps users explore beaches, activities, and experiences through an intuitive and visually engaging interface. It emphasizes a premium, easy-to-use experience with smooth navigation, modern design, and performance-focused development that reflects a luxury beach lifestyle.', NULL, NULL, NULL, NULL, 'Mobile', 1, NULL, 'case-studies/boujee-beachin-app', NULL, 4, 5, 1, '2025-12-08 15:54:30', '2026-01-28 08:29:32'),
(34, NULL, 'portfolio/567b670d339d3bdbc2e320aec079ef56.webp', 'portfolio/back-images/406ac581f2e210560a14a6f5fb398518.webp', 'Wood Land', 'Woodland is a concept-driven mobile application designed and developed by AppsNation that allows users to explore books through reading and listening while connecting with a community of readers. The app emphasizes a clean, distraction-free interface with a modern and immersive experience that feels personal and engaging.', NULL, NULL, NULL, NULL, 'Mobile', 1, NULL, 'case-studies/wood-land-app', NULL, 2, 3, 1, '2025-12-08 15:54:59', '2026-01-28 08:30:43'),
(35, NULL, 'portfolio/c78920ae87b579fd8f91306305c05fe5.webp', 'portfolio/back-images/baadf4c64c4ef187d9c026c34560ea1e.webp', 'Neuro Knights', 'Neuro Knights is a strategy-based mobile game designed and developed by AppsNation. The app delivers an engaging, immersive experience with intuitive controls, challenging gameplay, and visually appealing graphics, keeping players entertained while providing a seamless and smooth performance across devices.', NULL, NULL, NULL, NULL, 'Mobile', 1, NULL, 'case-studies/neuro-knights-app', NULL, NULL, NULL, NULL, '2025-12-10 15:07:34', '2026-01-28 08:47:32'),
(37, NULL, 'portfolio/2520957107520f0b07fe49ac518073f5.webp', 'portfolio/back-images/796caf1f05f16427ef6c9a34aca324b8.webp', 'Grave Love App', 'Grave Love is a digital platform designed and developed by AppsNation that allows users to care for their loved onesРђЎ graves from anywhere in the world. The app provides a respectful and emotionally sensitive experience, connecting families with local service providers while ensuring trust, transparency, and reliable completion of grave care requests with photo and video proof.', NULL, NULL, NULL, NULL, 'Mobile', 0, NULL, 'case-studies/grave-love-app', NULL, NULL, NULL, NULL, '2026-01-28 08:49:28', '2026-01-28 10:53:56'),
(38, NULL, 'portfolio/726a08cd4aafab793d4774a494868436.webp', 'portfolio/back-images/e216eeae1667045e522c28fb4a45f4b2.webp', 'Couple App', 'Couple App is a concept-based mobile platform designed and developed by AppsNation to help modern couples plan, organize, and celebrate their special moments together. The app streamlines wedding planning by tracking guests, managing tasks, and creating a romantic, emotionally meaningful experience that keeps couples connected throughout their journey.', NULL, NULL, NULL, NULL, 'Mobile', 0, NULL, 'case-studies/couple-app', NULL, NULL, NULL, NULL, '2026-01-28 08:52:38', '2026-01-28 10:55:25'),
(39, NULL, 'portfolio/26c1e0dc7cbe131d484dc57207468c9c.webp', 'portfolio/back-images/57172e8a511225f4ec3a0064bdb23343.webp', 'Royal Relax', 'Royal Relax is a spa booking and management platform designed and developed by AppsNation. The app allows clients to schedule services effortlessly while giving spa managers full control over appointments, staff, and payments. With a focus on calm, luxury, and ease, it delivers a seamless, branded experience that enhances customer satisfaction and business efficiency.', NULL, NULL, NULL, NULL, 'Mobile', 0, NULL, 'case-studies/royal-relax-spa', NULL, NULL, NULL, NULL, '2026-01-28 09:02:55', '2026-01-28 09:03:56'),
(40, NULL, 'portfolio/dcfe6677a175348ed8347ac187ddeab9.webp', 'portfolio/back-images/3fef28c4fef59e007b6f393a5f240ffe.webp', 'Load Board', 'Load Board is a logistics-focused mobile platform designed and developed by AppsNation to connect shippers with carriers efficiently. The app streamlines load posting, booking, and tracking processes, providing a user-friendly and reliable experience that optimizes operations for both businesses and transport providers.', NULL, NULL, NULL, NULL, 'Web', 0, NULL, 'case-studies/load-board', NULL, NULL, NULL, NULL, '2026-01-28 09:08:44', '2026-03-17 08:31:08'),
(41, NULL, 'portfolio/8a5410ad93752fbc09e7c018b9b52c84.webp', 'portfolio/back-images/5ee13fcce60d8be71078682065ee810d.webp', 'All Traders App', 'All Traders is a concept-driven mobile platform designed and developed by AppsNation to connect buyers and sellers seamlessly. The app provides an intuitive interface for browsing, trading, and managing transactions, delivering a smooth and efficient experience that supports business growth and user engagement.', NULL, NULL, NULL, NULL, 'Mobile', 0, NULL, 'case-studies/all-traders-app', NULL, NULL, NULL, NULL, '2026-01-28 09:13:07', '2026-01-28 09:13:07'),
(42, NULL, 'portfolio/93b9d8b731c64ab798ffd7e6b9647982.webp', 'portfolio/back-images/26000abf30b0e4c98fc4bdf01eff53a2.webp', 'Mike Mathis App', 'is a mentoring-focused mobile application designed and developed by AppsNation. The app enables seamless mentor discovery, chat interaction, and progress tracking, providing a simple, goal-oriented, and engaging experience for both mentors and mentees.', NULL, NULL, NULL, NULL, 'Mobile', 0, NULL, 'case-studies/mike-mathis-app', NULL, NULL, NULL, NULL, '2026-01-28 09:16:33', '2026-01-28 09:16:33'),
(43, NULL, 'portfolio/022a2332b825df005a4652002dee341b.webp', 'portfolio/back-images/91d55c99f725a71b986661ed607ed394.webp', 'Mover Web', 'Mover Web is a web platform designed and developed by AppsNation to simplify the moving experience. The app connects customers with trusted moving professionals and ensures a smooth, efficient, and stress-free journey from booking to move-in, focusing on convenience, reliability, and user satisfaction.', NULL, NULL, NULL, NULL, 'Web', 0, NULL, 'case-studies/mover-web', NULL, NULL, NULL, NULL, '2026-01-28 10:22:51', '2026-01-28 10:22:51'),
(44, NULL, 'portfolio/170110da1e8ac3f5310d0a7640c071d5.webp', 'portfolio/back-images/2c935a841afe54419680e80f91725d49.webp', 'Mover App', 'Mover App is a mobile platform designed and developed by AppsNation to redefine the moving experience. The app connects customers with trusted moving professionals, offering a seamless, efficient, and stress-free journey from booking to move-in, ensuring every move is smooth and hassle-free.', NULL, NULL, NULL, NULL, 'Mobile', 0, NULL, 'case-studies/mover-app', NULL, NULL, NULL, NULL, '2026-01-28 10:24:23', '2026-01-28 10:24:23'),
(45, NULL, 'portfolio/f8d58f1621ad75321f1b27412866b97f.webp', 'portfolio/back-images/6b92cb2d071e6d723bc2780d75405f8a.webp', 'Gym App', 'Gym App is a fitness-focused mobile application designed and developed by AppsNation to help users track workouts, manage training plans, and monitor progress effectively. The app provides a clean, intuitive, and engaging experience that motivates users to achieve their fitness goals while offering personalized guidance and performance insights.', NULL, NULL, NULL, NULL, 'Mobile', 0, NULL, 'case-studies/gym-app', NULL, NULL, NULL, NULL, '2026-01-28 10:25:52', '2026-01-28 10:25:52'),
(46, NULL, 'portfolio/2aaee4b7caa23b0ae724c19c2ecc4c03.webp', 'portfolio/back-images/454e5221afdadc508505905b1cf04a49.webp', 'Gym Web', 'Gym Web is a fitness management platform designed and developed by AppsNation to help users track workouts, manage training plans, and monitor progress online. The platform provides a clean, intuitive, and engaging experience, offering personalized guidance and performance insights to support users in achieving their fitness goals.', NULL, NULL, NULL, NULL, 'Web', 0, NULL, 'case-studies/gym-web', NULL, NULL, NULL, NULL, '2026-01-28 10:29:31', '2026-01-28 10:29:31'),
(47, NULL, 'portfolio/930a21462824bde046dfaa860afa70ac.webp', 'portfolio/back-images/c07ea89091f60ba9d7de08e8948305d7.webp', 'Loyalty', 'Loyalty app is a web platform designed and developed by AppsNation to provide a seamless and rewarding shopping experience. Beyond cashback deals, the platform focuses on building trust with users through an intuitive interface, robust security, and a smooth, convenient, and secure shopping journey.', NULL, NULL, NULL, NULL, 'Web', 0, NULL, 'case-studies/loyalty-web', NULL, NULL, NULL, NULL, '2026-01-28 10:31:53', '2026-01-28 10:31:53'),
