(1, 'Android', 'techstack/d9aacbe2a349d86bdbb824c2e3164183.webp', 'Android Studio is a feature-rich and highly versatile framework for developing Android applications. It is an official Integrated Development Environment (IDE) for developing Android apps. AppsNation has years of expertise developing highly functional Android apps using Android Studio.', NULL, NULL, 4, 5, 1, 1, 0, 1, 0, 1, 0, 1, 1, 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-05-09 03:57:09', '2025-11-06 15:08:48'),
