(27, 'C#', 'techstack/e2d6e2da3caf5305debec0cdeb8e30a0.webp', 'C# is an incredibly flexible programming language that is object-oriented (OOP) and one of the finest programming languages for gaming.\r\n\r\nAllow us to use our years of C# development experience to design your bespoke AR application', NULL, NULL, 86, 87, 1, 0, 0, 1, 0, 0, 0, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2022-05-25 07:48:09', '2025-01-10 15:08:04'),
